SELECT SOCIAL_ID, USER_ID, PROVIDER, PROVIDER_EMAIL, CREATED_AT
FROM USER_SOCIAL
WHERE USER_ID = #{userId}

SELECT COUNT(*)
FROM USER_SOCIAL
WHERE USER_ID = #{userId} AND PROVIDER = #{provider}

SELECT SOCIAL_ID, USER_ID, PROVIDER, PROVIDER_EMAIL, CREATED_AT
FROM USER_SOCIAL
WHERE PROVIDER = #{provider} AND PROVIDER_EMAIL = #{providerEmail}
